   423→func (am *DefaultAccountManager) handleGroupsPropagationSettings(ctx context.Context, oldSettings, newSettings *types.Settings, userID, accountID string) {
   424→	if oldSettings.GroupsPropagationEnabled != newSettings.GroupsPropagationEnabled {
   425→		if newSettings.GroupsPropagationEnabled {
   426→			am.StoreEvent(ctx, userID, accountID, accountID, activity.UserGroupPropagationEnabled, nil)
   427→		} else {
   428→			am.StoreEvent(ctx, userID, accountID, accountID, activity.UserGroupPropagationDisabled, nil)
   429→		}
   430→	}
   431→}
