   433→func (am *DefaultAccountManager) handleInactivityExpirationSettings(ctx context.Context, oldSettings, newSettings *types.Settings, userID, accountID string) error {
   434→	if newSettings.PeerInactivityExpirationEnabled {
   435→		if oldSettings.PeerInactivityExpiration != newSettings.PeerInactivityExpiration {
   436→			am.StoreEvent(ctx, userID, accountID, accountID, activity.AccountPeerInactivityExpirationDurationUpdated, nil)
   437→			am.checkAndSchedulePeerInactivityExpiration(ctx, accountID)
   438→		}
   439→	} else {
   440→		if oldSettings.PeerInactivityExpirationEnabled != newSettings.PeerInactivityExpirationEnabled {
   441→			event := activity.AccountPeerInactivityExpirationEnabled
   442→			if !newSettings.PeerInactivityExpirationEnabled {
   443→				event = activity.AccountPeerInactivityExpirationDisabled
   444→				am.peerInactivityExpiry.Cancel(ctx, []string{accountID})
   445→			} else {
   446→				am.checkAndSchedulePeerInactivityExpiration(ctx, accountID)
   447→			}
   448→			am.StoreEvent(ctx, userID, accountID, accountID, event, nil)
   449→		}
   450→	}
   451→
   452→	return nil
   453→}
