   455→func (am *DefaultAccountManager) peerLoginExpirationJob(ctx context.Context, accountID string) func() (time.Duration, bool) {
   456→	return func() (time.Duration, bool) {
   457→		unlock := am.Store.AcquireWriteLockByUID(ctx, accountID)
   458→		defer unlock()
   459→
   460→		expiredPeers, err := am.getExpiredPeers(ctx, accountID)
   461→		if err != nil {
   462→			return peerSchedulerRetryInterval, true
   463→		}
   464→
   465→		var peerIDs []string
   466→		for _, peer := range expiredPeers {
   467→			peerIDs = append(peerIDs, peer.ID)
   468→		}
   469→
   470→		log.WithContext(ctx).Debugf("discovered %d peers to expire for account %s", len(peerIDs), accountID)
   471→
   472→		if err := am.expireAndUpdatePeers(ctx, accountID, expiredPeers); err != nil {
   473→			log.WithContext(ctx).Errorf("failed updating account peers while expiring peers for account %s", accountID)
   474→			return peerSchedulerRetryInterval, true
   475→		}
   476→
   477→		return am.getNextPeerExpiration(ctx, accountID)
   478→	}
   479→}
   480→
   481→func (am *DefaultAccountManager) checkAndSchedulePeerLoginExpiration(ctx context.Context, accountID string) {
   482→	am.peerLoginExpiry.Cancel(ctx, []string{accountID})
   483→	if nextRun, ok := am.getNextPeerExpiration(ctx, accountID); ok {
   484→		go am.peerLoginExpiry.Schedule(ctx, nextRun, accountID, am.peerLoginExpirationJob(ctx, accountID))
   485→	}
   486→}
