   488→// peerInactivityExpirationJob marks login expired for all inactive peers and returns the minimum duration in which the next peer of the account will expire by inactivity if found
   489→func (am *DefaultAccountManager) peerInactivityExpirationJob(ctx context.Context, accountID string) func() (time.Duration, bool) {
   490→	return func() (time.Duration, bool) {
   491→		unlock := am.Store.AcquireWriteLockByUID(ctx, accountID)
   492→		defer unlock()
   493→
   494→		inactivePeers, err := am.getInactivePeers(ctx, accountID)
   495→		if err != nil {
   496→			log.WithContext(ctx).Errorf("failed getting inactive peers for account %s", accountID)
   497→			return peerSchedulerRetryInterval, true
   498→		}
   499→
   500→		var peerIDs []string
   501→		for _, peer := range inactivePeers {
   502→			peerIDs = append(peerIDs, peer.ID)
   503→		}
   504→
   505→		log.Debugf("discovered %d peers to expire for account %s", len(peerIDs), accountID)
   506→
   507→		if err := am.expireAndUpdatePeers(ctx, accountID, inactivePeers); err != nil {
   508→			log.Errorf("failed updating account peers while expiring peers for account %s", accountID)
   509→			return peerSchedulerRetryInterval, true
   510→		}
   511→
   512→		return am.getNextInactivePeerExpiration(ctx, accountID)
   513→	}
   514→}
