   548→func (am *DefaultAccountManager) warmupIDPCache(ctx context.Context, store cacheStore.StoreInterface) error {
   549→	cold, err := am.isCacheCold(ctx, store)
   550→	if err != nil {
   551→		return err
   552→	}
   553→
   554→	if !cold {
   555→		log.WithContext(ctx).Debug("cache already populated, skipping warm up")
   556→		return nil
   557→	}
   558→
   559→	if delayStr, ok := os.LookupEnv("NB_IDP_CACHE_WARMUP_DELAY"); ok {
   560→		delay, err := time.ParseDuration(delayStr)
   561→		if err != nil {
   562→			return fmt.Errorf("invalid IDP warmup delay: %w", err)
   563→		}
   564→		time.Sleep(delay)
   565→	}
   566→
   567→	userData, err := am.idpManager.GetAllAccounts(ctx)
   568→	if err != nil {
   569→		return err
   570→	}
   571→	log.WithContext(ctx).Infof("%d entries received from IdP management", len(userData))
   572→
   573→	// If the Identity Provider does not support writing AppMetadata,
   574→	// in cases like this, we expect it to return all users in an "unset" field.
   575→	// We iterate over the users in the "unset" field, look up their AccountID in our store, and
   576→	// update their AppMetadata with the AccountID.
   577→	if unsetData, ok := userData[idp.UnsetAccountID]; ok {
   578→		for _, user := range unsetData {
   579→			accountID, err := am.Store.GetAccountByUser(ctx, user.ID)
   580→			if err == nil {
   581→				data := userData[accountID.Id]
   582→				if data == nil {
   583→					data = make([]*idp.UserData, 0, 1)
   584→				}
   585→
   586→				user.AppMetadata.WTAccountID = accountID.Id
   587→
   588→				userData[accountID.Id] = append(data, user)
   589→			}
   590→		}
   591→	}
   592→	delete(userData, idp.UnsetAccountID)
   593→
   594→	rcvdUsers := 0
   595→	for accountID, users := range userData {
   596→		rcvdUsers += len(users)
   597→		err = am.cacheManager.Set(am.ctx, accountID, users, cacheEntryExpiration())
   598→		if err != nil {
   599→			return err
   600→		}
   601→	}
   602→	log.WithContext(ctx).Infof("warmed up IDP cache with %d entries for %d accounts", rcvdUsers, len(userData))
   603→	return nil
   604→}
   605→
   606→// isCacheCold checks if the cache needs warming up.
   607→func (am *DefaultAccountManager) isCacheCold(ctx context.Context, store cacheStore.StoreInterface) (bool, error) {
   608→	if store.GetType() != redis.RedisType {
   609→		return true, nil
   610→	}
   611→
   612→	accountID, err := am.Store.GetAnyAccountID(ctx)
   613→	if err != nil {
   614→		if sErr, ok := status.FromError(err); ok && sErr.Type() == status.NotFound {
   615→			return true, nil
   616→		}
   617→		return false, err
   618→	}
   619→
   620→	_, err = store.Get(ctx, accountID)
   621→	if err == nil {
   622→		return false, nil
   623→	}
   624→
   625→	if notFoundErr := new(cacheStore.NotFound); errors.As(err, &notFoundErr) {
   626→		return true, nil
   627→	}
   628→
   629→	return false, fmt.Errorf("failed to check cache: %w", err)
   630→}
