   632→// DeleteAccount deletes an account and all its users from local store and from the remote IDP if the requester is an admin and account owner
   633→func (am *DefaultAccountManager) DeleteAccount(ctx context.Context, accountID, userID string) error {
   634→	unlock := am.Store.AcquireWriteLockByUID(ctx, accountID)
   635→	defer unlock()
   636→	account, err := am.Store.GetAccount(ctx, accountID)
   637→	if err != nil {
   638→		return err
   639→	}
   640→
   641→	allowed, err := am.permissionsManager.ValidateUserPermissions(ctx, accountID, userID, modules.Accounts, operations.Delete)
   642→	if err != nil {
   643→		return fmt.Errorf("failed to validate user permissions: %w", err)
   644→	}
   645→
   646→	if !allowed {
   647→		return status.Errorf(status.PermissionDenied, "user is not allowed to delete account. Only account owner can delete account")
   648→	}
   649→
   650→	userInfosMap, err := am.BuildUserInfosForAccount(ctx, accountID, userID, maps.Values(account.Users))
   651→	if err != nil {
   652→		return status.Errorf(status.Internal, "failed to build user infos for account %s: %v", accountID, err)
   653→	}
   654→
   655→	for _, otherUser := range account.Users {
   656→		if otherUser.Id == userID {
   657→			continue
   658→		}
   659→
   660→		if otherUser.IsServiceUser {
   661→			err = am.deleteServiceUser(ctx, accountID, userID, otherUser)
   662→			if err != nil {
   663→				return err
   664→			}
   665→			continue
   666→		}
   667→
   668→		userInfo, ok := userInfosMap[otherUser.Id]
   669→		if !ok {
   670→			return status.Errorf(status.NotFound, "user info not found for user %s", otherUser.Id)
   671→		}
   672→
   673→		_, deleteUserErr := am.deleteRegularUser(ctx, accountID, userID, userInfo)
   674→		if deleteUserErr != nil {
   675→			return deleteUserErr
   676→		}
   677→	}
   678→
   679→	userInfo, ok := userInfosMap[userID]
   680→	if ok {
   681→		_, err = am.deleteRegularUser(ctx, accountID, userID, userInfo)
   682→		if err != nil {
   683→			log.WithContext(ctx).Errorf("failed deleting user %s. error: %s", userID, err)
   684→			return err
   685→		}
   686→	}
   687→
   688→	err = am.Store.DeleteAccount(ctx, account)
   689→	if err != nil {
   690→		log.WithContext(ctx).Errorf("failed deleting account %s. error: %s", accountID, err)
   691→		return err
   692→	}
   693→	// cancel peer login expiry job
   694→	am.peerLoginExpiry.Cancel(ctx, []string{account.Id})
   695→
   696→	log.WithContext(ctx).Debugf("account %s deleted", accountID)
   697→	return nil
   698→}
