   705→// GetAccountIDByUserID retrieves the account ID based on the userID provided.
   706→// If user does have an account, it returns the user's account ID.
   707→// If the user doesn't have an account, it creates one using the provided domain.
   708→// Returns the account ID or an error if none is found or created.
   709→func (am *DefaultAccountManager) GetAccountIDByUserID(ctx context.Context, userID, domain string) (string, error) {
   710→	if userID == "" {
   711→		return "", status.Errorf(status.NotFound, "no valid userID provided")
   712→	}
   713→
   714→	accountID, err := am.Store.GetAccountIDByUserID(ctx, store.LockingStrengthShare, userID)
   715→	if err != nil {
   716→		if s, ok := status.FromError(err); ok && s.Type() == status.NotFound {
   717→			account, err := am.GetOrCreateAccountByUser(ctx, userID, domain)
   718→			if err != nil {
   719→				return "", status.Errorf(status.NotFound, "account not found or created for user id: %s", userID)
   720→			}
   721→
   722→			if err = am.addAccountIDToIDPAppMeta(ctx, userID, account.Id); err != nil {
   723→				return "", err
   724→			}
   725→			return account.Id, nil
   726→		}
   727→		return "", err
   728→	}
   729→	return accountID, nil
   730→}
