   736→// addAccountIDToIDPAppMeta update user's  app metadata in idp manager
   737→func (am *DefaultAccountManager) addAccountIDToIDPAppMeta(ctx context.Context, userID string, accountID string) error {
   738→	if !isNil(am.idpManager) {
   739→		// user can be nil if it wasn't found (e.g., just created)
   740→		user, err := am.lookupUserInCache(ctx, userID, accountID)
   741→		if err != nil {
   742→			return err
   743→		}
   744→
   745→		if user != nil && user.AppMetadata.WTAccountID == accountID {
   746→			// it was already set, so we skip the unnecessary update
   747→			log.WithContext(ctx).Debugf("skipping IDP App Meta update because accountID %s has been already set for user %s",
   748→				accountID, userID)
   749→			return nil
   750→		}
   751→
   752→		err = am.idpManager.UpdateUserAppMetadata(ctx, userID, idp.AppMetadata{WTAccountID: accountID})
   753→		if err != nil {
   754→			return status.Errorf(status.Internal, "updating user's app metadata failed with: %v", err)
   755→		}
   756→		// refresh cache to reflect the update
   757→		_, err = am.refreshCache(ctx, accountID)
   758→		if err != nil {
   759→			return err
   760→		}
   761→	}
   762→	return nil
   763→}
