   765→func (am *DefaultAccountManager) loadAccount(ctx context.Context, accountID any) (any, []cacheStore.Option, error) {
   766→	log.WithContext(ctx).Debugf("account %s not found in cache, reloading", accountID)
   767→	accountIDString := fmt.Sprintf("%v", accountID)
   768→
   769→	accountUsers, err := am.Store.GetAccountUsers(ctx, store.LockingStrengthShare, accountIDString)
   770→	if err != nil {
   771→		return nil, nil, err
   772→	}
   773→
   774→	userData, err := am.idpManager.GetAccount(ctx, accountIDString)
   775→	if err != nil {
   776→		return nil, nil, err
   777→	}
   778→	log.WithContext(ctx).Debugf("%d entries received from IdP management for account %s", len(userData), accountIDString)
   779→
   780→	dataMap := make(map[string]*idp.UserData, len(userData))
   781→	for _, datum := range userData {
   782→		dataMap[datum.ID] = datum
   783→	}
   784→
   785→	matchedUserData := make([]*idp.UserData, 0)
   786→	for _, user := range accountUsers {
   787→		if user.IsServiceUser {
   788→			continue
   789→		}
   790→		datum, ok := dataMap[user.Id]
   791→		if !ok {
   792→			log.WithContext(ctx).Warnf("user %s not found in IDP", user.Id)
   793→			continue
   794→		}
   795→		matchedUserData = append(matchedUserData, datum)
   796→	}
   797→
   798→	data, err := msgpack.Marshal(matchedUserData)
   799→	if err != nil {
   800→		return nil, nil, err
   801→	}
   802→
   803→	return data, []cacheStore.Option{cacheStore.WithExpiration(cacheEntryExpiration())}, nil
   804→}
