   821→// lookupUserInCache looks up user in the IdP cache and returns it. If the user wasn't found, the function returns nil
   822→func (am *DefaultAccountManager) lookupUserInCache(ctx context.Context, userID string, accountID string) (*idp.UserData, error) {
   823→	accountUsers, err := am.Store.GetAccountUsers(ctx, store.LockingStrengthShare, accountID)
   824→	if err != nil {
   825→		return nil, err
   826→	}
   827→
   828→	users := make(map[string]userLoggedInOnce, len(accountUsers))
   829→	// ignore service users and users provisioned by integrations than are never logged in
   830→	for _, user := range accountUsers {
   831→		if user.IsServiceUser {
   832→			continue
   833→		}
   834→		if user.Issued == types.UserIssuedIntegration {
   835→			continue
   836→		}
   837→		users[user.Id] = userLoggedInOnce(!user.GetLastLogin().IsZero())
   838→	}
   839→	log.WithContext(ctx).Debugf("looking up user %s of account %s in cache", userID, accountID)
   840→	userData, err := am.lookupCache(ctx, users, accountID)
   841→	if err != nil {
   842→		return nil, err
   843→	}
   844→
   845→	for _, datum := range userData {
   846→		if datum.ID == userID {
   847→			return datum, nil
   848→		}
   849→	}
   850→
   851→	// add extra check on external cache manager. We may get to this point when the user is not yet findable in IDP,
   852→	// or it didn't have its metadata updated with am.addAccountIDToIDPAppMeta
   853→	user, err := am.Store.GetUserByUserID(ctx, store.LockingStrengthShare, userID)
   854→	if err != nil {
   855→		log.WithContext(ctx).Errorf("failed finding user %s in account %s", userID, accountID)
   856→		return nil, err
   857→	}
   858→
   859→	key := user.IntegrationReference.CacheKey(accountID, userID)
   860→	ud, err := am.externalCacheManager.Get(am.ctx, key)
   861→	if err != nil {
   862→		log.WithContext(ctx).Debugf("failed to get externalCache for key: %s, error: %s", key, err)
   863→	}
   864→
   865→	return ud, nil
   866→}
