   872→// getAccountFromCache returns user data for a given account ensuring that cache load happens only once
   873→func (am *DefaultAccountManager) getAccountFromCache(ctx context.Context, accountID string, forceReload bool) ([]*idp.UserData, error) {
   874→	am.cacheMux.Lock()
   875→	loadingChan := am.cacheLoading[accountID]
   876→	if loadingChan == nil {
   877→		loadingChan = make(chan struct{})
   878→		am.cacheLoading[accountID] = loadingChan
   879→		am.cacheMux.Unlock()
   880→
   881→		defer func() {
   882→			am.cacheMux.Lock()
   883→			delete(am.cacheLoading, accountID)
   884→			close(loadingChan)
   885→			am.cacheMux.Unlock()
   886→		}()
   887→
   888→		if forceReload {
   889→			err := am.cacheManager.Delete(am.ctx, accountID)
   890→			if err != nil {
   891→				return nil, err
   892→			}
   893→		}
   894→
   895→		return am.cacheManager.Get(am.ctx, accountID)
   896→	}
   897→	am.cacheMux.Unlock()
   898→
   899→	log.WithContext(ctx).Debugf("one request to get account %s is already running", accountID)
   900→
   901→	select {
   902→	case <-loadingChan:
   903→		// channel has been closed meaning cache was loaded => simply return from cache
   904→		return am.cacheManager.Get(am.ctx, accountID)
   905→	case <-time.After(5 * time.Second):
   906→		return nil, fmt.Errorf("timeout while waiting for account %s cache to reload", accountID)
   907→	}
   908→}
   909→
   910→func (am *DefaultAccountManager) lookupCache(ctx context.Context, accountUsers map[string]userLoggedInOnce, accountID string) ([]*idp.UserData, error) {
   911→	var data []*idp.UserData
   912→	var err error
   913→
   914→	maxAttempts := 2
   915→
   916→	data, err = am.getAccountFromCache(ctx, accountID, false)
   917→	if err != nil {
   918→		return nil, err
   919→	}
   920→
   921→	for attempt := 1; attempt <= maxAttempts; attempt++ {
   922→		if am.isCacheFresh(ctx, accountUsers, data) {
   923→			return data, nil
   924→		}
   925→
   926→		if attempt > 1 {
   927→			time.Sleep(200 * time.Millisecond)
   928→		}
   929→
   930→		log.WithContext(ctx).Infof("refreshing cache for account %s", accountID)
   931→		data, err = am.refreshCache(ctx, accountID)
   932→		if err != nil {
   933→			return nil, err
   934→		}
   935→
   936→		if attempt == maxAttempts {
   937→			log.WithContext(ctx).Warnf("cache for account %s reached maximum refresh attempts (%d)", accountID, maxAttempts)
   938→		}
   939→	}
   940→
   941→	return data, nil
   942→}
   943→
   944→// isCacheFresh checks if the cache is refreshed already by comparing the accountUsers with the cache data by user count and user invite status
   945→func (am *DefaultAccountManager) isCacheFresh(ctx context.Context, accountUsers map[string]userLoggedInOnce, data []*idp.UserData) bool {
   946→	userDataMap := make(map[string]*idp.UserData, len(data))
   947→	for _, datum := range data {
   948→		userDataMap[datum.ID] = datum
   949→	}
   950→
   951→	// the accountUsers ID list of non integration users from store, we check if cache has all of them
   952→	// as result of for loop knownUsersCount will have number of users are not presented in the cashed
   953→	knownUsersCount := len(accountUsers)
   954→	for user, loggedInOnce := range accountUsers {
   955→		if datum, ok := userDataMap[user]; ok {
   956→			// check if the matching user data has a pending invite and if the user has logged in once, forcing the cache to be refreshed
   957→			if datum.AppMetadata.WTPendingInvite != nil && *datum.AppMetadata.WTPendingInvite && loggedInOnce == true { //nolint:gosimple
   958→				log.WithContext(ctx).Infof("user %s has a pending invite and has logged in once, cache invalid", user)
   959→				return false
   960→			}
   961→			knownUsersCount--
   962→			continue
   963→		}
   964→		log.WithContext(ctx).Debugf("cache doesn't know about %s user", user)
   965→	}
   966→
   967→	// if we know users that are not yet in cache more likely cache is outdated
   968→	if knownUsersCount > 0 {
   969→		log.WithContext(ctx).Infof("cache invalid. Users unknown to the cache: %d", knownUsersCount)
   970→		return false
   971→	}
   972→
   973→	return true
   974→}
