   976→func (am *DefaultAccountManager) removeUserFromCache(ctx context.Context, accountID, userID string) error {
   977→	data, err := am.getAccountFromCache(ctx, accountID, false)
   978→	if err != nil {
   979→		return err
   980→	}
   981→
   982→	for i, datum := range data {
   983→		if datum.ID == userID {
   984→			data = append(data[:i], data[i+1:]...)
   985→			break
   986→		}
   987→	}
   988→
   989→	return am.cacheManager.Set(am.ctx, accountID, data, cacheEntryExpiration())
   990→}
