   992→// updateAccountDomainAttributesIfNotUpToDate updates the account domain attributes if they are not up to date and then, saves the account changes
   993→func (am *DefaultAccountManager) updateAccountDomainAttributesIfNotUpToDate(ctx context.Context, accountID string, userAuth nbcontext.UserAuth,
   994→	primaryDomain bool,
   995→) error {
   996→	if userAuth.Domain == "" {
   997→		log.WithContext(ctx).Errorf("claims don't contain a valid domain, skipping domain attributes update. Received claims: %v", userAuth)
   998→		return nil
   999→	}
  1000→
  1001→	unlockAccount := am.Store.AcquireWriteLockByUID(ctx, accountID)
  1002→	defer unlockAccount()
  1003→
  1004→	accountDomain, domainCategory, err := am.Store.GetAccountDomainAndCategory(ctx, store.LockingStrengthShare, accountID)
  1005→	if err != nil {
  1006→		log.WithContext(ctx).Errorf("error getting account domain and category: %v", err)
  1007→		return err
  1008→	}
  1009→
  1010→	if domainIsUpToDate(accountDomain, domainCategory, userAuth) {
  1011→		return nil
  1012→	}
  1013→
  1014→	user, err := am.Store.GetUserByUserID(ctx, store.LockingStrengthShare, userAuth.UserId)
  1015→	if err != nil {
  1016→		log.WithContext(ctx).Errorf("error getting user: %v", err)
  1017→		return err
  1018→	}
  1019→
  1020→	newDomain := accountDomain
  1021→	newCategoty := domainCategory
  1022→
  1023→	lowerDomain := strings.ToLower(userAuth.Domain)
  1024→	if accountDomain != lowerDomain && user.HasAdminPower() {
  1025→		newDomain = lowerDomain
  1026→	}
  1027→
  1028→	if accountDomain == lowerDomain {
  1029→		newCategoty = userAuth.DomainCategory
  1030→	}
  1031→
  1032→	return am.Store.UpdateAccountDomainAttributes(ctx, accountID, newDomain, newCategoty, primaryDomain)
  1033→}
  1034→
  1035→// handleExistingUserAccount handles existing User accounts and update its domain attributes.
  1036→// If there is no primary domain account yet, we set the account as primary for the domain. Otherwise,
  1037→// we compare the account's ID with the domain account ID, and if they don't match, we set the account as
  1038→// non-primary account for the domain. We don't merge accounts at this stage, because of cases when a domain
  1039→// was previously unclassified or classified as public so N users that logged int that time, has they own account
  1040→// and peers that shouldn't be lost.
  1041→func (am *DefaultAccountManager) handleExistingUserAccount(
  1042→	ctx context.Context,
  1043→	userAccountID string,
  1044→	domainAccountID string,
  1045→	userAuth nbcontext.UserAuth,
  1046→) error {
  1047→	primaryDomain := domainAccountID == "" || userAccountID == domainAccountID
  1048→	err := am.updateAccountDomainAttributesIfNotUpToDate(ctx, userAccountID, userAuth, primaryDomain)
  1049→	if err != nil {
  1050→		return err
