  1116→// redeemInvite checks whether user has been invited and redeems the invite
  1117→func (am *DefaultAccountManager) redeemInvite(ctx context.Context, accountID string, userID string) error {
  1118→	// only possible with the enabled IdP manager
  1119→	if am.idpManager == nil {
  1120→		log.WithContext(ctx).Warnf("invites only work with enabled IdP manager")
  1121→		return nil
  1122→	}
  1123→
  1124→	user, err := am.lookupUserInCache(ctx, userID, accountID)
  1125→	if err != nil {
  1126→		return err
  1127→	}
  1128→
  1129→	if user == nil {
  1130→		return status.Errorf(status.NotFound, "user %s not found in the IdP", userID)
  1131→	}
  1132→
  1133→	if user.AppMetadata.WTPendingInvite != nil && *user.AppMetadata.WTPendingInvite {
  1134→		log.WithContext(ctx).Infof("redeeming invite for user %s account %s", userID, accountID)
  1135→		// User has already logged in, meaning that IdP should have set wt_pending_invite to false.
  1136→		// Our job is to just reload cache.
  1137→		go func() {
  1138→			_, err = am.refreshCache(ctx, accountID)
  1139→			if err != nil {
  1140→				log.WithContext(ctx).Warnf("failed reloading cache when redeeming user %s under account %s", userID, accountID)
  1141→				return
  1142→			}
  1143→			log.WithContext(ctx).Debugf("user %s of account %s redeemed invite", user.ID, accountID)
  1144→			am.StoreEvent(ctx, userID, userID, accountID, activity.UserJoined, nil)
  1145→		}()
  1146→	}
  1147→
  1148→	return nil
  1149→}
