  1182→func (am *DefaultAccountManager) GetAccountIDFromUserAuth(ctx context.Context, userAuth nbcontext.UserAuth) (string, string, error) {
  1183→	if userAuth.UserId == "" {
  1184→		return "", "", errors.New(emptyUserID)
  1185→	}
  1186→	if am.singleAccountMode && am.singleAccountModeDomain != "" {
  1187→		// This section is mostly related to self-hosted installations.
  1188→		// We override incoming domain claims to group users under a single account.
  1189→		userAuth.Domain = am.singleAccountModeDomain
  1190→		userAuth.DomainCategory = types.PrivateCategory
  1191→		log.WithContext(ctx).Debugf("overriding JWT Domain and DomainCategory claims since single account mode is enabled")
  1192→	}
  1193→
  1194→	accountID, err := am.getAccountIDWithAuthorizationClaims(ctx, userAuth)
  1195→	if err != nil {
  1196→		return "", "", err
  1197→	}
  1198→
  1199→	user, err := am.Store.GetUserByUserID(ctx, store.LockingStrengthShare, userAuth.UserId)
  1200→	if err != nil {
  1201→		// this is not really possible because we got an account by user ID
  1202→		return "", "", status.Errorf(status.NotFound, "user %s not found", userAuth.UserId)
  1203→	}
  1204→
  1205→	if userAuth.IsChild {
  1206→		return accountID, user.Id, nil
  1207→	}
  1208→
  1209→	if err := am.permissionsManager.ValidateAccountAccess(ctx, accountID, user, false); err != nil {
  1210→		return "", "", err
  1211→	}
  1212→
  1213→	if !user.IsServiceUser && userAuth.Invited {
  1214→		err = am.redeemInvite(ctx, accountID, user.Id)
  1215→		if err != nil {
  1216→			return "", "", err
  1217→		}
  1218→	}
  1219→
  1220→	return accountID, user.Id, nil
  1221→}
