  1223→// syncJWTGroups processes the JWT groups for a user, updates the account based on the groups,
  1224→// and propagates changes to peers if group propagation is enabled.
  1225→// requires userAuth to have been ValidateAndParseToken and EnsureUserAccessByJWTGroups by the AuthManager
  1226→func (am *DefaultAccountManager) SyncUserJWTGroups(ctx context.Context, userAuth nbcontext.UserAuth) error {
  1227→	if userAuth.IsChild || userAuth.IsPAT {
  1228→		return nil
  1229→	}
  1230→
  1231→	settings, err := am.Store.GetAccountSettings(ctx, store.LockingStrengthShare, userAuth.AccountId)
  1232→	if err != nil {
  1233→		return err
  1234→	}
  1235→
  1236→	if settings == nil || !settings.JWTGroupsEnabled {
  1237→		return nil
  1238→	}
  1239→
  1240→	if settings.JWTGroupsClaimName == "" {
  1241→		log.WithContext(ctx).Debugf("JWT groups are enabled but no claim name is set")
  1242→		return nil
  1243	}
  1244→
  1245→	unlockAccount := am.Store.AcquireWriteLockByUID(ctx, userAuth.AccountId)
  1246→	defer func() {
  1247→		if unlockAccount != nil {
  1248→			unlockAccount()
  1249→		}
  1250→	}()
  1251→
  1252→	var addNewGroups []string
  1253→	var removeOldGroups []string
  1254→	var hasChanges bool
  1255→	var user *types.User
  1256→	err = am.Store.ExecuteInTransaction(ctx, func(transaction store.Store) error {
  1257→		user, err = transaction.GetUserByUserID(ctx, store.LockingStrengthShare, userAuth.UserId)
  1258→		if err != nil {
  1259→			return fmt.Errorf("error getting user: %w", err)
  1260→		}
  1261→
  1262→		groups, err := transaction.GetAccountGroups(ctx, store.LockingStrengthShare, userAuth.AccountId)
  1263→		if err != nil {
  1264→			return fmt.Errorf("error getting account groups: %w", err)
  1265→		}
  1266→
  1267→		changed, updatedAutoGroups, newGroupsToCreate, err := am.getJWTGroupsChanges(user, groups, userAuth.Groups)
  1268→		if err != nil {
  1269→			return fmt.Errorf("error getting JWT groups changes: %w", err)
  1270→		}
  1271→
  1272→		hasChanges = changed
  1273→		// skip update if no changes
  1274→		if !changed {
  1275→			return nil
  1276→		}
  1277→
  1278→		if err = transaction.SaveGroups(ctx, store.LockingStrengthUpdate, userAuth.AccountId, newGroupsToCreate); err != nil {
  1279→			return fmt.Errorf("error saving groups: %w", err)
  1280→		}
  1281→
  1282→		addNewGroups = util.Difference(updatedAutoGroups, user.AutoGroups)
  1283→		removeOldGroups = util.Difference(user.AutoGroups, updatedAutoGroups)
  1284→
  1285→		user.AutoGroups = updatedAutoGroups
  1286→		if err = transaction.SaveUser(ctx, store.LockingStrengthUpdate, user); err != nil {
  1287→			return fmt.Errorf("error saving user: %w", err)
  1288→		}
  1289→
  1290→		// Propagate changes to peers if group propagation is enabled
  1291→		if settings.GroupsPropagationEnabled {
  1292→			groups, err = transaction.GetAccountGroups(ctx, store.LockingStrengthShare, userAuth.AccountId)
  1293→			if err != nil {
  1294→				return fmt.Errorf("error getting account groups: %w", err)
  1295→			}
  1296→
  1297→			groupsMap := make(map[string]*types.Group, len(groups))
  1298→			for _, group := range groups {
  1299→				groupsMap[group.ID] = group
  1300→			}
  1301→
  1302→			peers, err := transaction.GetUserPeers(ctx, store.LockingStrengthShare, userAuth.AccountId, userAuth.UserId)
  1303→			if err != nil {
  1304→				return fmt.Errorf("error getting user peers: %w", err)
  1305→			}
  1306→
  1307→			updatedGroups, err := updateUserPeersInGroups(groupsMap, peers, addNewGroups, removeOldGroups)
  1308→			if err != nil {
  1309→				return fmt.Errorf("error modifying user peers in groups: %w", err)
  1310→			}
  1311→
  1312→			if err = transaction.SaveGroups(ctx, store.LockingStrengthUpdate, userAuth.AccountId, updatedGroups); err != nil {
  1313→				return fmt.Errorf("error saving groups: %w", err)
  1314→			}
  1315→
  1316→			if err = transaction.IncrementNetworkSerial(ctx, store.LockingStrengthUpdate, userAuth.AccountId); err != nil {
  1317→				return fmt.Errorf("error incrementing network serial: %w", err)
  1318→			}
  1319→		}
  1320→		unlockAccount()
  1321→		unlockAccount = nil
  1322→
  1323→		return nil
  1324→	})
  1325→	if err != nil {
  1326→		return err
  1327→	}
  1328→
  1329→	if !hasChanges {
  1330→		return nil
  1331→	}
  1332→
  1333→	for _, g := range addNewGroups {
  1334→		group, err := am.Store.GetGroupByID(ctx, store.LockingStrengthShare, userAuth.AccountId, g)
  1335→		if err != nil {
  1336→			log.WithContext(ctx).Debugf("group %s not found while saving user activity event of account %s", g, userAuth.AccountId)
  1337→		} else {
  1338→			meta := map[string]any{
  1339→				"group": group.Name, "group_id": group.ID,
  1340→				"is_service_user": user.IsServiceUser, "user_name": user.ServiceUserName,
  1341→			}
  1342→			am.StoreEvent(ctx, user.Id, user.Id, userAuth.AccountId, activity.GroupAddedToUser, meta)
  1343→		}
  1344→	}
  1345→
  1346→	for _, g := range removeOldGroups {
  1347→		group, err := am.Store.GetGroupByID(ctx, store.LockingStrengthShare, userAuth.AccountId, g)
  1348→		if err != nil {
  1349→			log.WithContext(ctx).Debugf("group %s not found while saving user activity event of account %s", g, userAuth.AccountId)
  1350→		} else {
  1351→			meta := map[string]any{
  1352→				"group": group.Name, "group_id": group.ID,
  1353→				"is_service_user": user.IsServiceUser, "user_name": user.ServiceUserName,
  1354→			}
  1355→			am.StoreEvent(ctx, user.Id, user.Id, userAuth.AccountId, activity.GroupRemovedFromUser, meta)
  1356→		}
  1357→	}
  1358→
  1359→	if settings.GroupsPropagationEnabled {
  1360→		removedGroupAffectsPeers, err := areGroupChangesAffectPeers(ctx, am.Store, userAuth.AccountId, removeOldGroups)
  1361→		if err != nil {
  1362→			return err
  1363→		}
  1364→
  1365→		newGroupsAffectsPeers, err := areGroupChangesAffectPeers(ctx, am.Store, userAuth.AccountId, addNewGroups)
  1366→		if err != nil {
  1367→			return err
  1368→		}
  1369→
  1370→		if removedGroupAffectsPeers || newGroupsAffectsPeers {
  1371→			log.WithContext(ctx).Tracef("user %s: JWT group membership changed, updating account peers", userAuth.UserId)
  1372→			am.BufferUpdateAccountPeers(ctx, userAuth.AccountId)
  1373→		}
  1374→	}
  1375→
  1376→	return nil
  1377→}
  1378→
  1379→// getAccountIDWithAuthorizationClaims retrieves an account ID using JWT Claims.
  1380→// if domain is not private or domain is invalid, it will return the account ID by user ID.
  1381→// if domain is of the PrivateCategory category, it will evaluate
  1382→// if account is new, existing or if there is another account with the same domain
  1383→//
  1384→// Use cases:
  1385→//
  1386→// New user + New account + New domain -> create account, user role = owner (if private domain, index domain)
  1387→//
  1388→// New user + New account + Existing Private Domain -> add user to the existing account, user role = user (not admin)
  1389→//
  1390→// New user + New account + Existing Public Domain -> create account, user role = owner
  1391→//
  1392→// Existing user + Existing account + Existing Domain -> Nothing changes (if private, index domain)
  1393→//
  1394→// Existing user + Existing account + Existing Indexed Domain -> Nothing changes
  1395→//
  1396→// Existing user + Existing account + Existing domain reclassified Domain as private -> Nothing changes (index domain)
  1397→//
  1398→// UserAuth IsChild -> checks that account exists
  1399→func (am *DefaultAccountManager) getAccountIDWithAuthorizationClaims(ctx context.Context, userAuth nbcontext.UserAuth) (string, error) {
  1400→	log.WithContext(ctx).Tracef("getting account with authorization claims. User ID: \"%s\", Account ID: \"%s\", Domain: \"%s\", Domain Category: \"%s\"",
  1401→		userAuth.UserId, userAuth.AccountId, userAuth.Domain, userAuth.DomainCategory)
  1402→
  1403→	if userAuth.UserId == "" {
  1404→		return "", errors.New(emptyUserID)
  1405→	}
  1406→
  1407→	if userAuth.IsChild {
  1408→		exists, err := am.Store.AccountExists(ctx, store.LockingStrengthShare, userAuth.AccountId)
  1409→		if err != nil || !exists {
  1410→			return "", err
  1411→		}
  1412→		return userAuth.AccountId, nil
  1413→	}
  1414→
  1415→	if userAuth.DomainCategory != types.PrivateCategory || !isDomainValid(userAuth.Domain) {
  1416→		return am.GetAccountIDByUserID(ctx, userAuth.UserId, userAuth.Domain)
  1417→	}
  1418→
  1419→	if userAuth.AccountId != "" {
  1420→		return am.handlePrivateAccountWithIDFromClaim(ctx, userAuth)
  1421→	}
  1422→
  1423→	// We checked if the domain has a primary account already
  1424→	domainAccountID, cancel, err := am.getPrivateDomainWithGlobalLock(ctx, userAuth.Domain)
  1425→	if cancel != nil {
  1426→		defer cancel()
  1427→	}
  1428→	if err != nil {
  1429→		return "", err
  1430→	}
  1431→
  1432→	userAccountID, err := am.Store.GetAccountIDByUserID(ctx, store.LockingStrengthShare, userAuth.UserId)
  1433→	if handleNotFound(err) != nil {
  1434→		log.WithContext(ctx).Errorf("error getting account ID by user ID: %v", err)
  1435→		return "", err
  1436→	}
  1437→
  1438→	if userAccountID != "" {
  1439→		if err = am.handleExistingUserAccount(ctx, userAccountID, domainAccountID, userAuth); err != nil {
  1440→			return "", err
  1441→		}
  1442→
  1443→		return userAccountID, nil
  1444→	}
  1445→
  1446→	if domainAccountID != "" {
  1447→		return am.addNewUserToDomainAccount(ctx, domainAccountID, userAuth)
  1448→	}
  1449→
  1450→	return am.addNewPrivateAccount(ctx, domainAccountID, userAuth)
  1451→}
  1452→func (am *DefaultAccountManager) getPrivateDomainWithGlobalLock(ctx context.Context, domain string) (string, context.CancelFunc, error) {
  1453→	domainAccountID, err := am.Store.GetAccountIDByPrivateDomain(ctx, store.LockingStrengthShare, domain)
  1454→	if handleNotFound(err) != nil {
  1455→
  1456→		log.WithContext(ctx).Errorf(errorGettingDomainAccIDFmt, err)
  1457→		return "", nil, err
  1458→	}
  1459→
  1460→	if domainAccountID != "" {
  1461→		return domainAccountID, nil, nil
  1462→	}
  1463→
  1464→	log.WithContext(ctx).Debugf("no primary account found for domain %s, acquiring global lock", domain)
  1465→	cancel := am.Store.AcquireGlobalLock(ctx)
  1466→
  1467→	// check again if the domain has a primary account because of simultaneous requests
  1468→	domainAccountID, err = am.Store.GetAccountIDByPrivateDomain(ctx, store.LockingStrengthShare, domain)
  1469→	if handleNotFound(err) != nil {
  1470→		cancel()
  1471→		log.WithContext(ctx).Errorf(errorGettingDomainAccIDFmt, err)
  1472→		return "", nil, err
  1473→	}
  1474→
  1475→	return domainAccountID, cancel, nil
  1476→}
  1477→
  1478→func (am *DefaultAccountManager) handlePrivateAccountWithIDFromClaim(ctx context.Context, userAuth nbcontext.UserAuth) (string, error) {
  1479→	userAccountID, err := am.Store.GetAccountIDByUserID(ctx, store.LockingStrengthShare, userAuth.UserId)
  1480→	if err != nil {
  1481→		log.WithContext(ctx).Errorf("error getting account ID by user ID: %v", err)
  1482→		return "", err
  1483→	}
  1484→
  1485→	if userAccountID != userAuth.AccountId {
  1486→		return "", fmt.Errorf("user %s is not part of the account id %s", userAuth.UserId, userAuth.AccountId)
  1487→	}
  1488→
  1489→	accountDomain, domainCategory, err := am.Store.GetAccountDomainAndCategory(ctx, store.LockingStrengthShare, userAuth.AccountId)
  1490→	if handleNotFound(err) != nil {
  1491→		log.WithContext(ctx).Errorf("error getting account domain and category: %v", err)
  1492→		return "", err
  1493→	}
  1494→
  1495→	if domainIsUpToDate(accountDomain, domainCategory, userAuth) {
  1496→		return userAuth.AccountId, nil
  1497→	}
  1498→
  1499→	// We checked if the domain has a primary account already
  1500→	domainAccountID, err := am.Store.GetAccountIDByPrivateDomain(ctx, store.LockingStrengthShare, userAuth.Domain)
  1501→	if handleNotFound(err) != nil {
  1502→		log.WithContext(ctx).Errorf(errorGettingDomainAccIDFmt, err)
  1503→		return "", err
  1504→	}
  1505→
  1506→	err = am.handleExistingUserAccount(ctx, userAuth.AccountId, domainAccountID, userAuth)
  1507→	if err != nil {
  1508→		return "", err
  1509→	}
  1510→
  1511→	return userAuth.AccountId, nil
  1512→}
  1513→
  1514→func handleNotFound(err error) error {
  1515→	if err == nil {
  1516→		return nil
  1517→	}
  1518→
  1519→	e, ok := status.FromError(err)
  1520→	if !ok || e.Type() != status.NotFound {
  1521→		return err
  1522→	}
  1523→	return nil
  1524→}
  1525→
  1526→func domainIsUpToDate(domain string, domainCategory string, userAuth nbcontext.UserAuth) bool {
  1527→	return domainCategory == types.PrivateCategory || userAuth.DomainCategory != types.PrivateCategory || domain != userAuth.Domain
  1528→}
