  1530→func (am *DefaultAccountManager) SyncAndMarkPeer(ctx context.Context, accountID string, peerPubKey string, meta nbpeer.PeerSystemMeta, realIP net.IP) (*nbpeer.Peer, *types.NetworkMap, []*posture.Checks, error) {
  1531→	start := time.Now()
  1532→	defer func() {
  1533→		log.WithContext(ctx).Debugf("SyncAndMarkPeer: took %v", time.Since(start))
  1534→	}()
  1535→
  1536→	accountUnlock := am.Store.AcquireReadLockByUID(ctx, accountID)
  1537→	defer accountUnlock()
  1538→	peerUnlock := am.Store.AcquireWriteLockByUID(ctx, peerPubKey)
  1539→	defer peerUnlock()
  1540→
  1541→	peer, netMap, postureChecks, err := am.SyncPeer(ctx, types.PeerSync{WireGuardPubKey: peerPubKey, Meta: meta}, accountID)
  1542→	if err != nil {
  1543→		return nil, nil, nil, fmt.Errorf("error syncing peer: %w", err)
  1544→	}
  1545→
  1546→	err = am.MarkPeerConnected(ctx, peerPubKey, true, realIP, accountID)
  1547→	if err != nil {
  1548→		log.WithContext(ctx).Warnf("failed marking peer as connected %s %v", peerPubKey, err)
  1549→	}
  1550→
  1551→	return peer, netMap, postureChecks, nil
  1552→}
