  1760→func (am *DefaultAccountManager) GetOrCreateAccountByPrivateDomain(ctx context.Context, initiatorId, domain string) (*types.Account, bool, error) {
  1761→	cancel := am.Store.AcquireGlobalLock(ctx)
  1762→	defer cancel()
  1763→
  1764→	existingPrimaryAccountID, err := am.Store.GetAccountIDByPrivateDomain(ctx, store.LockingStrengthShare, domain)
  1765→	if handleNotFound(err) != nil {
  1766→		return nil, false, err
  1767→	}
  1768→
  1769→	// a primary account already exists for this private domain
  1770→	if err == nil {
  1771→		existingAccount, err := am.Store.GetAccount(ctx, existingPrimaryAccountID)
  1772→		if err != nil {
  1773→			return nil, false, err
  1774→		}
  1775→
  1776→		return existingAccount, false, nil
  1777→	}
  1778→
  1779→	// create a new account for this private domain
  1780→	// retry twice for new ID clashes
  1781→	for range 2 {
  1782→		accountId := xid.New().String()
  1783→
  1784→		exists, err := am.Store.AccountExists(ctx, store.LockingStrengthShare, accountId)
  1785→		if err != nil || exists {
  1786→			continue
  1787→		}
  1788→
  1789→		network := types.NewNetwork()
  1790→		peers := make(map[string]*nbpeer.Peer)
  1791→		users := make(map[string]*types.User)
  1792→		routes := make(map[route.ID]*route.Route)
  1793→		setupKeys := map[string]*types.SetupKey{}
  1794→		nameServersGroups := make(map[string]*nbdns.NameServerGroup)
  1795→
  1796→		dnsSettings := types.DNSSettings{
  1797→			DisabledManagementGroups: make([]string, 0),
  1798→		}
  1799→
  1800→		newAccount := &types.Account{
  1801→			Id:        accountId,
  1802→			CreatedAt: time.Now().UTC(),
  1803→			SetupKeys: setupKeys,
  1804→			Network:   network,
  1805→			Peers:     peers,
  1806→			Users:     users,
  1807→			// @todo check if using the MSP owner id here is ok
  1808→			CreatedBy:              initiatorId,
  1809→			Domain:                 strings.ToLower(domain),
  1810→			DomainCategory:         types.PrivateCategory,
  1811→			IsDomainPrimaryAccount: false,
  1812→			Routes:                 routes,
  1813→			NameServerGroups:       nameServersGroups,
  1814→			DNSSettings:            dnsSettings,
  1815→			Settings: &types.Settings{
  1816→				PeerLoginExpirationEnabled: true,
  1817→				PeerLoginExpiration:        types.DefaultPeerLoginExpiration,
  1818→				GroupsPropagationEnabled:   true,
  1819→				RegularUsersViewBlocked:    true,
  1820→
  1821→				PeerInactivityExpirationEnabled: false,
  1822→				PeerInactivityExpiration:        types.DefaultPeerInactivityExpiration,
  1823→				RoutingPeerDNSResolutionEnabled: true,
  1824→			},
  1825→		}
  1826→
  1827→		if err := newAccount.AddAllGroup(); err != nil {
  1828→			return nil, false, status.Errorf(status.Internal, "failed to add all group to new account by private domain")
  1829→		}
  1830→
  1831→		if err := am.Store.SaveAccount(ctx, newAccount); err != nil {
  1832→			log.WithContext(ctx).WithFields(log.Fields{
  1833→				"accountId": newAccount.Id,
  1834→				"domain":    domain,
  1835→			}).Errorf("failed to create new account: %v", err)
  1836→			return nil, false, err
  1837→		}
  1838→
  1839→		am.StoreEvent(ctx, initiatorId, newAccount.Id, accountId, activity.AccountCreated, nil)
  1840→		return newAccount, true, nil
  1841→	}
  1842→
  1843→	return nil, false, status.Errorf(status.Internal, "failed to get or create new account by private domain")
  1844→}
