  1884→// propagateUserGroupMemberships propagates all account users' group memberships to their peers.
  1885→// Returns true if any groups were modified, true if those updates affect peers and an error.
  1886→func propagateUserGroupMemberships(ctx context.Context, transaction store.Store, accountID string) (groupsUpdated bool, peersAffected bool, err error) {
  1887→	groups, err := transaction.GetAccountGroups(ctx, store.LockingStrengthShare, accountID)
  1888→	if err != nil {
  1889→		return false, false, err
  1890→	}
  1891→
  1892→	groupsMap := make(map[string]*types.Group, len(groups))
  1893→	for _, group := range groups {
  1894→		groupsMap[group.ID] = group
  1895→	}
  1896→
  1897→	users, err := transaction.GetAccountUsers(ctx, store.LockingStrengthShare, accountID)
  1898→	if err != nil {
  1899→		return false, false, err
  1900→	}
  1901→
  1902→	groupsToUpdate := make(map[string]*types.Group)
  1903→
  1904→	for _, user := range users {
  1905→		userPeers, err := transaction.GetUserPeers(ctx, store.LockingStrengthShare, accountID, user.Id)
  1906→		if err != nil {
  1907→			return false, false, err
  1908→		}
  1909→
  1910→		updatedGroups, err := updateUserPeersInGroups(groupsMap, userPeers, user.AutoGroups, nil)
  1911→		if err != nil {
  1912→			return false, false, err
  1913→		}
  1914→
  1915→		for _, group := range updatedGroups {
  1916→			groupsToUpdate[group.ID] = group
  1917→			groupsMap[group.ID] = group
  1918→		}
  1919→	}
  1920→
  1921→	if len(groupsToUpdate) == 0 {
  1922→		return false, false, nil
  1923→	}
  1924→
  1925→	peersAffected, err = areGroupChangesAffectPeers(ctx, transaction, accountID, maps.Keys(groupsToUpdate))
  1926→	if err != nil {
  1927→		return false, false, err
  1928→	}
  1929→
  1930→	err = transaction.SaveGroups(ctx, store.LockingStrengthUpdate, accountID, maps.Values(groupsToUpdate))
  1931→	if err != nil {
  1932→		return false, false, err
  1933→	}
  1934→
  1935→	return true, peersAffected, nil
  1936→}
