   510→// GetNextPeerExpiration returns the minimum duration in which the next peer of the account will expire if it was found.
   511→// If there is no peer that expires this function returns false and a duration of 0.
   512→// This function only considers peers that haven't been expired yet and that are connected.
   513→func (a *Account) GetNextPeerExpiration() (time.Duration, bool) {
   514→	peersWithExpiry := a.GetPeersWithExpiration()
   515→	if len(peersWithExpiry) == 0 {
   516→		return 0, false
   517→	}
   518→	var nextExpiry *time.Duration
   519→	for _, peer := range peersWithExpiry {
   520→		// consider only connected peers because others will require login on connecting to the management server
   521→		if peer.Status.LoginExpired || !peer.Status.Connected {
   522→			continue
   523→		}
   524→		_, duration := peer.LoginExpired(a.Settings.PeerLoginExpiration)
   525→		if nextExpiry == nil || duration < *nextExpiry {
   526→			// if expiration is below 1s return 1s duration
   527→			// this avoids issues with ticker that can't be set to < 0
   528→			if duration < time.Second {
   529→				return time.Second, true
   530→			}
   531→			nextExpiry = &duration
   532→		}
   533→	}
   534→
   535→	if nextExpiry == nil {
   536→		return 0, false
   537→	}
   538→
   539→	return *nextExpiry, true
   540→}
