   627→// DeletePeer deletes peer from the account cleaning up all the references
   628→func (a *Account) DeletePeer(peerID string) {
   629→	// delete peer from groups
   630→	for _, g := range a.Groups {
   631→		for i, pk := range g.Peers {
   632→			if pk == peerID {
   633→				g.Peers = append(g.Peers[:i], g.Peers[i+1:]...)
   634→				break
   635→			}
   636→		}
   637→	}
   638→
   639→	for _, r := range a.Routes {
   640→		if r.Peer == peerID {
   641→			r.Enabled = false
   642→			r.Peer = ""
   643→		}
   644→	}
   645→
   646→	for i, r := range a.NetworkRouters {
   647→		if r.Peer == peerID {
   648→			a.NetworkRouters = append(a.NetworkRouters[:i], a.NetworkRouters[i+1:]...)
   649→			break
   650→		}
   651→	}
   652→
   653→	delete(a.Peers, peerID)
   654→	a.Network.IncSerial()
   655→}
