   782→func (a *Account) Copy() *Account {
   783→	peers := map[string]*nbpeer.Peer{}
   784→	for id, peer := range a.Peers {
   785→		peers[id] = peer.Copy()
   786→	}
   787→
   788→	users := map[string]*User{}
   789→	for id, user := range a.Users {
   790→		users[id] = user.Copy()
   791→	}
   792→
   793→	setupKeys := map[string]*SetupKey{}
   794→	for id, key := range a.SetupKeys {
   795→		setupKeys[id] = key.Copy()
   796→	}
   797→
   798→	groups := map[string]*Group{}
   799→	for id, group := range a.Groups {
   800→		groups[id] = group.Copy()
   801→	}
   802→
   803→	policies := []*Policy{}
   804→	for _, policy := range a.Policies {
   805→		policies = append(policies, policy.Copy())
   806→	}
   807→
   808→	routes := map[route.ID]*route.Route{}
   809→	for id, r := range a.Routes {
   810→		routes[id] = r.Copy()
