   893→// UserGroupsAddToPeers adds groups to all peers of user
   894→func (a *Account) UserGroupsAddToPeers(userID string, groups ...string) map[string][]string {
   895→	groupUpdates := make(map[string][]string)
   896→
   897→	userPeers := make(map[string]struct{})
   898→	for pid, peer := range a.Peers {
   899→		if peer.UserID == userID {
   900→			userPeers[pid] = struct{}{}
   901→		}
   902→	}
   903→
   904→	for _, gid := range groups {
   905→		group, ok := a.Groups[gid]
   906→		if !ok {
   907→			continue
   908→		}
   909→
   910→		oldPeers := group.Peers
   911→
   912→		groupPeers := make(map[string]struct{})
   913→		for _, pid := range group.Peers {
   914→			groupPeers[pid] = struct{}{}
   915→		}
   916→
   917→		for pid := range userPeers {
   918→			groupPeers[pid] = struct{}{}
   919→		}
   920→
   921→		group.Peers = group.Peers[:0]
   922→		for pid := range groupPeers {
   923→			group.Peers = append(group.Peers, pid)
   924→		}
   925→
   926→		groupUpdates[gid] = util.Difference(group.Peers, oldPeers)
   927→	}
   928→
   929→	return groupUpdates
   930→}
