   932→// UserGroupsRemoveFromPeers removes groups from all peers of user
   933→func (a *Account) UserGroupsRemoveFromPeers(userID string, groups ...string) map[string][]string {
   934→	groupUpdates := make(map[string][]string)
   935→
   936→	for _, gid := range groups {
   937→		group, ok := a.Groups[gid]
   938→		if !ok || group.Name == "All" {
   939→			continue
   940→		}
   941→
   942→		oldPeers := group.Peers
   943→
   944→		update := make([]string, 0, len(group.Peers))
   945→		for _, pid := range group.Peers {
   946→			peer, ok := a.Peers[pid]
   947→			if !ok {
   948→				continue
   949→			}
   950→			if peer.UserID != userID {
   951→				update = append(update, pid)
   952→			}
   953→		}
   954→		group.Peers = update
   955→		groupUpdates[gid] = util.Difference(oldPeers, group.Peers)
   956→	}
   957→
   958→	return groupUpdates
   959→}
