   961→// GetPeerConnectionResources for a given peer
   962→//
   963→// This function returns the list of peers and firewall rules that are applicable to a given peer.
   964→func (a *Account) GetPeerConnectionResources(ctx context.Context, peerID string, validatedPeersMap map[string]struct{}) ([]*nbpeer.Peer, []*FirewallRule) {
   965→	generateResources, getAccumulatedResources := a.connResourcesGenerator(ctx)
   966→	for _, policy := range a.Policies {
   967→		if !policy.Enabled {
   968→			continue
   969→		}
   970→
   971→		for _, rule := range policy.Rules {
   972→			if !rule.Enabled {
   973→				continue
   974→			}
   975→
   976→			sourcePeers, peerInSources := a.getAllPeersFromGroups(ctx, rule.Sources, peerID, policy.SourcePostureChecks, validatedPeersMap)
   977→			destinationPeers, peerInDestinations := a.getAllPeersFromGroups(ctx, rule.Destinations, peerID, nil, validatedPeersMap)
   978→
   979→			if rule.Bidirectional {
   980→				if peerInSources {
   981→					generateResources(rule, destinationPeers, FirewallRuleDirectionIN)
   982→				}
   983→				if peerInDestinations {
   984→					generateResources(rule, sourcePeers, FirewallRuleDirectionOUT)
   985→				}
   986→			}
   987→
   988→			if peerInSources {
   989→				generateResources(rule, destinationPeers, FirewallRuleDirectionOUT)
   990→			}
   991→
   992→			if peerInDestinations {
   993→				generateResources(rule, sourcePeers, FirewallRuleDirectionIN)
   994→			}
   995→		}
   996→	}
   997→
   998→	return getAccumulatedResources()
   999→}
  1000→
  1001→// connResourcesGenerator returns generator and accumulator function which returns the result of generator calls
  1002→//
  1003→// The generator function is used to generate the list of peers and firewall rules that are applicable to a given peer.
  1004→// It safe to call the generator function multiple times for same peer and different rules no duplicates will be
  1005→// generated. The accumulator function returns the result of all the generator calls.
  1006→func (a *Account) connResourcesGenerator(ctx context.Context) (func(*PolicyRule, []*nbpeer.Peer, int), func() ([]*nbpeer.Peer, []*FirewallRule)) {
  1007→	rulesExists := make(map[string]struct{})
  1008→	peersExists := make(map[string]struct{})
  1009→	rules := make([]*FirewallRule, 0)
  1010→	peers := make([]*nbpeer.Peer, 0)
  1011→
  1012→	all, err := a.GetGroupAll()
  1013→	if err != nil {
  1014→		log.WithContext(ctx).Errorf("failed to get group all: %v", err)
  1015→		all = &Group{}
  1016→	}
  1017→
  1018→	return func(rule *PolicyRule, groupPeers []*nbpeer.Peer, direction int) {
  1019→			isAll := (len(all.Peers) - 1) == len(groupPeers)
  1020→			for _, peer := range groupPeers {
  1021→				if peer == nil {
  1022→					continue
  1023→				}
  1024→
  1025→				if _, ok := peersExists[peer.ID]; !ok {
  1026→					peers = append(peers, peer)
  1027→					peersExists[peer.ID] = struct{}{}
  1028→				}
  1029→
  1030→				fr := FirewallRule{
  1031→					PolicyID:  rule.ID,
  1032→					PeerIP:    peer.IP.String(),
  1033→					Direction: direction,
  1034→					Action:    string(rule.Action),
  1035→					Protocol:  string(rule.Protocol),
  1036→				}
  1037→
  1038→				if isAll {
  1039→					fr.PeerIP = "0.0.0.0"
  1040→				}
  1041→
  1042→				ruleID := rule.ID + fr.PeerIP + strconv.Itoa(direction) +
  1043→					fr.Protocol + fr.Action + strings.Join(rule.Ports, ",")
  1044→				if _, ok := rulesExists[ruleID]; ok {
  1045→					continue
  1046→				}
  1047→				rulesExists[ruleID] = struct{}{}
  1048→
  1049→				if len(rule.Ports) == 0 && len(rule.PortRanges) == 0 {
  1050→					rules = append(rules, &fr)
  1051→					continue
  1052→				}
  1053→
  1054→				for _, port := range rule.Ports {
  1055→					pr := fr // clone rule and add set new port
  1056→					pr.Port = port
  1057→					rules = append(rules, &pr)
  1058→				}
  1059→
  1060→				for _, portRange := range rule.PortRanges {
  1061→					pr := fr
  1062→					pr.PortRange = portRange
  1063→					rules = append(rules, &pr)
  1064→				}
  1065→			}
  1066→		}, func() ([]*nbpeer.Peer, []*FirewallRule) {
  1067→			return peers, rules
  1068→		}
  1069→}
  1070→
  1071→// getAllPeersFromGroups for given peer ID and list of groups
  1072→//
  1073→// Returns a list of peers from specified groups that pass specified posture checks
  1074→// and a boolean indicating if the supplied peer ID exists within these groups.
  1075→//
  1076→// Important: Posture checks are applicable only to source group peers,
  1077→// for destination group peers, call this method with an empty list of sourcePostureChecksIDs
  1078→func (a *Account) getAllPeersFromGroups(ctx context.Context, groups []string, peerID string, sourcePostureChecksIDs []string, validatedPeersMap map[string]struct{}) ([]*nbpeer.Peer, bool) {
  1079→	peerInGroups := false
  1080→	uniquePeerIDs := a.getUniquePeerIDsFromGroupsIDs(ctx, groups)
  1081→	filteredPeers := make([]*nbpeer.Peer, 0, len(uniquePeerIDs))
  1082→	for _, p := range uniquePeerIDs {
  1083→		peer, ok := a.Peers[p]
  1084→		if !ok || peer == nil {
  1085→			continue
  1086→		}
  1087→
  1088→		// validate the peer based on policy posture checks applied
  1089→		isValid := a.validatePostureChecksOnPeer(ctx, sourcePostureChecksIDs, peer.ID)
  1090→		if !isValid {
  1091→			continue
  1092→		}
  1093→
  1094→		if _, ok := validatedPeersMap[peer.ID]; !ok {
  1095→			continue
  1096→		}
  1097→
  1098→		if peer.ID == peerID {
  1099→			peerInGroups = true
  1100→			continue
  1101→		}
  1102→
  1103→		filteredPeers = append(filteredPeers, peer)
  1104→	}
  1105→
  1106→	return filteredPeers, peerInGroups
  1107→}
