  1109→// validatePostureChecksOnPeer validates the posture checks on a peer
  1110→func (a *Account) validatePostureChecksOnPeer(ctx context.Context, sourcePostureChecksID []string, peerID string) bool {
  1111→	peer, ok := a.Peers[peerID]
  1112→	if !ok && peer == nil {
  1113→		return false
  1114→	}
  1115→
  1116→	for _, postureChecksID := range sourcePostureChecksID {
  1117→		postureChecks := a.GetPostureChecks(postureChecksID)
  1118→		if postureChecks == nil {
  1119→			continue
  1120→		}
  1121→
  1122→		for _, check := range postureChecks.GetChecks() {
  1123→			isValid, err := check.Check(ctx, *peer)
  1124→			if err != nil {
  1125→				log.WithContext(ctx).Debugf("an error occurred check %s: on peer: %s :%s", check.Name(), peer.ID, err.Error())
  1126→			}
  1127→			if !isValid {
  1128→				return false
  1129→			}
  1130→		}
  1131→	}
  1132→	return true
  1133→}
