  1144→// GetPeerRoutesFirewallRules gets the routes firewall rules associated with a routing peer ID for the account.
  1145→func (a *Account) GetPeerRoutesFirewallRules(ctx context.Context, peerID string, validatedPeersMap map[string]struct{}) []*RouteFirewallRule {
  1146→	routesFirewallRules := make([]*RouteFirewallRule, 0, len(a.Routes))
  1147→
  1148→	enabledRoutes, _ := a.getRoutingPeerRoutes(ctx, peerID)
  1149→	for _, route := range enabledRoutes {
  1150→		// If no access control groups are specified, accept all traffic.
  1151→		if len(route.AccessControlGroups) == 0 {
  1152→			defaultPermit := getDefaultPermit(route)
  1153→			routesFirewallRules = append(routesFirewallRules, defaultPermit...)
  1154→			continue
  1155→		}
  1156→
  1157→		distributionPeers := a.getDistributionGroupsPeers(route)
  1158→
  1159→		for _, accessGroup := range route.AccessControlGroups {
  1160→			policies := GetAllRoutePoliciesFromGroups(a, []string{accessGroup})
  1161→			rules := a.getRouteFirewallRules(ctx, peerID, policies, route, validatedPeersMap, distributionPeers)
  1162→			routesFirewallRules = append(routesFirewallRules, rules...)
  1163→		}
  1164→	}
  1165→
  1166→	return routesFirewallRules
  1167→}
