  1169→func (a *Account) getRouteFirewallRules(ctx context.Context, peerID string, policies []*Policy, route *route.Route, validatedPeersMap map[string]struct{}, distributionPeers map[string]struct{}) []*RouteFirewallRule {
  1170→	var fwRules []*RouteFirewallRule
  1171→	for _, policy := range policies {
  1172→		if !policy.Enabled {
  1173→			continue
  1174→		}
  1175→
  1176→		for _, rule := range policy.Rules {
  1177→			if !rule.Enabled {
  1178→				continue
  1179→			}
  1180→
  1181→			rulePeers := a.getRulePeers(rule, policy.SourcePostureChecks, peerID, distributionPeers, validatedPeersMap)
  1182→			rules := generateRouteFirewallRules(ctx, route, rule, rulePeers, FirewallRuleDirectionIN)
  1183→			fwRules = append(fwRules, rules...)
  1184→		}
  1185→	}
  1186→	return fwRules
  1187→}
