  1189→func (a *Account) getRulePeers(rule *PolicyRule, postureChecks []string, peerID string, distributionPeers map[string]struct{}, validatedPeersMap map[string]struct{}) []*nbpeer.Peer {
  1190→	distPeersWithPolicy := make(map[string]struct{})
  1191→	for _, id := range rule.Sources {
  1192→		group := a.Groups[id]
  1193→		if group == nil {
  1194→			continue
  1195→		}
  1196→
  1197→		for _, pID := range group.Peers {
  1198→			if pID == peerID {
  1199→				continue
  1200→			}
  1201→			_, distPeer := distributionPeers[pID]
  1202→			_, valid := validatedPeersMap[pID]
  1203→			if distPeer && valid && a.validatePostureChecksOnPeer(context.Background(), postureChecks, pID) {
  1204→				distPeersWithPolicy[pID] = struct{}{}
  1205→			}
  1206→		}
  1207→	}
  1208→
  1209→	distributionGroupPeers := make([]*nbpeer.Peer, 0, len(distPeersWithPolicy))
  1210→	for pID := range distPeersWithPolicy {
  1211→		peer := a.Peers[pID]
  1212→		if peer == nil {
  1213→			continue
  1214→		}
  1215→		distributionGroupPeers = append(distributionGroupPeers, peer)
  1216→	}
  1217→	return distributionGroupPeers
  1218→}
