  1235→func getDefaultPermit(route *route.Route) []*RouteFirewallRule {
  1236→	var rules []*RouteFirewallRule
  1237→
  1238→	sources := []string{"0.0.0.0/0"}
  1239→	if route.Network.Addr().Is6() {
  1240→		sources = []string{"::/0"}
  1241→	}
  1242→	rule := RouteFirewallRule{
  1243→		SourceRanges: sources,
  1244→		Action:       string(PolicyTrafficActionAccept),
  1245→		Destination:  route.Network.String(),
  1246→		Protocol:     string(PolicyRuleProtocolALL),
  1247→		Domains:      route.Domains,
  1248→		IsDynamic:    route.IsDynamic(),
  1249→		RouteID:      route.ID,
  1250→	}
  1251→
  1252→	rules = append(rules, &rule)
  1253→
  1254→	// dynamic routes always contain an IPv4 placeholder as destination, hence we must add IPv6 rules additionally
  1255→	if route.IsDynamic() {
  1256→		ruleV6 := rule
  1257→		ruleV6.SourceRanges = []string{"::/0"}
  1258→		rules = append(rules, &ruleV6)
  1259→	}
  1260→
  1261→	return rules
  1262→}
