  1264→// GetAllRoutePoliciesFromGroups retrieves route policies associated with the specified access control groups
  1265→// and returns a list of policies that have rules with destinations matching the specified groups.
  1266→func GetAllRoutePoliciesFromGroups(account *Account, accessControlGroups []string) []*Policy {
  1267→	routePolicies := make([]*Policy, 0)
  1268→	for _, groupID := range accessControlGroups {
  1269→		group, ok := account.Groups[groupID]
  1270→		if !ok {
  1271→			continue
  1272→		}
  1273→
  1274→		for _, policy := range account.Policies {
  1275→			for _, rule := range policy.Rules {
  1276→				exist := slices.ContainsFunc(rule.Destinations, func(groupID string) bool {
  1277→					return groupID == group.ID
  1278→				})
  1279→				if exist {
  1280→					routePolicies = append(routePolicies, policy)
  1281→					continue
  1282→				}
  1283→			}
  1284→		}
  1285→	}
  1286→
  1287→	return routePolicies
  1288→}
