  1341→// GetNetworkResourcesRoutesToSync returns network routes for syncing with a specific peer and its ACL peers.
  1342→func (a *Account) GetNetworkResourcesRoutesToSync(ctx context.Context, peerID string, resourcePolicies map[string][]*Policy, routers map[string]map[string]*routerTypes.NetworkRouter) (bool, []*route.Route, map[string]struct{}) {
  1343→	var isRoutingPeer bool
  1344→	var routes []*route.Route
  1345→	allSourcePeers := make(map[string]struct{}, len(a.Peers))
  1346→
  1347→	for _, resource := range a.NetworkResources {
  1348→		if !resource.Enabled {
  1349→			continue
  1350→		}
  1351→
  1352→		var addSourcePeers bool
  1353→
  1354→		networkRoutingPeers, exists := routers[resource.NetworkID]
  1355→		if exists {
  1356→			if router, ok := networkRoutingPeers[peerID]; ok {
  1357→				isRoutingPeer, addSourcePeers = true, true
  1358→				routes = append(routes, a.getNetworkResourcesRoutes(resource, peerID, router, resourcePolicies)...)
  1359→			}
  1360→		}
  1361→
  1362→		addedResourceRoute := false
  1363→		for _, policy := range resourcePolicies[resource.ID] {
  1364→			peers := a.getUniquePeerIDsFromGroupsIDs(ctx, policy.SourceGroups())
  1365→			if addSourcePeers {
  1366→				for _, pID := range a.getPostureValidPeers(peers, policy.SourcePostureChecks) {
  1367→					allSourcePeers[pID] = struct{}{}
  1368→				}
  1369→			} else if slices.Contains(peers, peerID) && a.validatePostureChecksOnPeer(ctx, policy.SourcePostureChecks, peerID) {
  1370→				// add routes for the resource if the peer is in the distribution group
  1371→				for peerId, router := range networkRoutingPeers {
  1372→					routes = append(routes, a.getNetworkResourcesRoutes(resource, peerId, router, resourcePolicies)...)
  1373→				}
  1374→				addedResourceRoute = true
  1375→			}
  1376→			if addedResourceRoute {
  1377→				break
  1378→			}
  1379→		}
  1380→	}
  1381→
  1382→	return isRoutingPeer, routes, allSourcePeers
  1383→}
  1384→
  1385→func (a *Account) getPostureValidPeers(inputPeers []string, postureChecksIDs []string) []string {
  1386→	var dest []string
  1387→	for _, peerID := range inputPeers {
  1388→		if a.validatePostureChecksOnPeer(context.Background(), postureChecksIDs, peerID) {
  1389→			dest = append(dest, peerID)
  1390→		}
  1391→	}
  1392→	return dest
  1393→}
  1394→
  1395→func (a *Account) getUniquePeerIDsFromGroupsIDs(ctx context.Context, groups []string) []string {
  1396→	peerIDs := make(map[string]struct{}, len(groups)) // we expect at least one peer per group as initial capacity
  1397→	for _, groupID := range groups {
  1398→		group := a.GetGroup(groupID)
  1399→		if group == nil {
  1400→			log.WithContext(ctx).Warnf("group %s doesn't exist under account %s, will continue map generation without it", groupID, a.Id)
  1401→			continue
  1402→		}
  1403→
  1404→		if group.IsGroupAll() || len(groups) == 1 {
  1405→			return group.Peers
  1406→		}
  1407→
  1408→		for _, peerID := range group.Peers {
  1409→			peerIDs[peerID] = struct{}{}
  1410→		}
  1411→	}
  1412→
  1413→	ids := make([]string, 0, len(peerIDs))
  1414→	for peerID := range peerIDs {
  1415→		ids = append(ids, peerID)
  1416→	}
  1417→
  1418→	return ids
  1419→}
  1420→
  1421→// getNetworkResources filters and returns a list of network resources associated with the given network ID.
  1422→func (a *Account) getNetworkResources(networkID string) []*resourceTypes.NetworkResource {
  1423→	var resources []*resourceTypes.NetworkResource
  1424→	for _, resource := range a.NetworkResources {
  1425→		if resource.NetworkID == networkID {
  1426→			resources = append(resources, resource)
  1427→		}
  1428→	}
  1429→	return resources
  1430→}
  1431→
  1432→// GetPoliciesForNetworkResource retrieves the list of policies that apply to a specific network resource.
  1433→// A policy is deemed applicable if its destination groups include any of the given network resource groups
  1434→// or if its destination resource explicitly matches the provided resource.
  1435→func (a *Account) GetPoliciesForNetworkResource(resourceId string) []*Policy {
  1436→	var resourceAppliedPolicies []*Policy
  1437→
  1438→	networkResourceGroups := a.getNetworkResourceGroups(resourceId)
  1439→
  1440→	for _, policy := range a.Policies {
  1441→		if !policy.Enabled {
  1442→			continue
  1443→		}
  1444→
  1445→		for _, rule := range policy.Rules {
  1446→			if !rule.Enabled {
  1447→				continue
  1448→			}
  1449→
  1450→			if rule.DestinationResource.ID == resourceId {
  1451→				resourceAppliedPolicies = append(resourceAppliedPolicies, policy)
  1452→				break
  1453→			}
  1454→
  1455→			for _, group := range networkResourceGroups {
  1456→				if slices.Contains(rule.Destinations, group.ID) {
  1457→					resourceAppliedPolicies = append(resourceAppliedPolicies, policy)
  1458→					break
  1459→				}
  1460→			}
  1461→		}
  1462→	}
  1463→
  1464→	return resourceAppliedPolicies
  1465→}
  1466→
  1467→func (a *Account) GetPoliciesAppliedInNetwork(networkID string) []string {
  1468→	networkResources := a.getNetworkResources(networkID)
  1469→
  1470→	policiesIDs := map[string]struct{}{}
  1471→	for _, resource := range networkResources {
  1472→		resourceAppliedPolicies := a.GetPoliciesForNetworkResource(resource.ID)
  1473→		for _, policy := range resourceAppliedPolicies {
  1474→			policiesIDs[policy.ID] = struct{}{}
  1475→		}
  1476→	}
  1477→
  1478→	result := make([]string, 0, len(policiesIDs))
  1479→	for id := range policiesIDs {
  1480→		result = append(result, id)
  1481→	}
  1482→
  1483→	return result
  1484→}
  1485→
  1486→// getNetworkResourcesRoutes convert the network resources list to routes list.
  1487→func (a *Account) getNetworkResourcesRoutes(resource *resourceTypes.NetworkResource, peerId string, router *routerTypes.NetworkRouter, resourcePolicies map[string][]*Policy) []*route.Route {
  1488→	resourceAppliedPolicies := resourcePolicies[resource.ID]
  1489→
  1490→	var routes []*route.Route
  1491→	// distribute the resource routes only if there is policy applied to it
  1492→	if len(resourceAppliedPolicies) > 0 {
  1493→		peer := a.GetPeer(peerId)
  1494→		if peer != nil {
  1495→			routes = append(routes, resource.ToRoute(peer, router))
  1496→		}
  1497→	}
  1498→
  1499→	return routes
  1500→}
  1501→
  1502→func (a *Account) GetResourceRoutersMap() map[string]map[string]*routerTypes.NetworkRouter {
  1503→	routers := make(map[string]map[string]*routerTypes.NetworkRouter)
  1504→
  1505→	for _, router := range a.NetworkRouters {
  1506→		if !router.Enabled {
  1507→			continue
  1508→		}
  1509→
  1510→		if routers[router.NetworkID] == nil {
  1511→			routers[router.NetworkID] = make(map[string]*routerTypes.NetworkRouter)
  1512→		}
  1513→
  1514→		if router.Peer != "" {
  1515→			routers[router.NetworkID][router.Peer] = router
  1516→			continue
  1517→		}
  1518→
  1519→		for _, peerGroup := range router.PeerGroups {
  1520→			g := a.Groups[peerGroup]
  1521→			if g != nil {
  1522→				for _, peerID := range g.Peers {
  1523→					routers[router.NetworkID][peerID] = router
  1524→				}
  1525→			}
  1526→		}
  1527→	}
  1528→
  1529→	return routers
  1530→}
  1531→
  1532→// getPoliciesSourcePeers collects all unique peers from the source groups defined in the given policies.
  1533→func getPoliciesSourcePeers(policies []*Policy, groups map[string]*Group) map[string]struct{} {
  1534→	sourcePeers := make(map[string]struct{})
  1535→
  1536→	for _, policy := range policies {
  1537→		for _, rule := range policy.Rules {
  1538→			for _, sourceGroup := range rule.Sources {
  1539→				group := groups[sourceGroup]
  1540→				if group == nil {
  1541→					continue
  1542→				}
  1543→
  1544→				for _, peer := range group.Peers {
  1545→					sourcePeers[peer] = struct{}{}
  1546→				}
  1547→			}
  1548→		}
  1549→	}
  1550→
  1551→	return sourcePeers
  1552→}
  1553→
  1554→// AddAllGroup to account object if it doesn't exist
  1555→func (a *Account) AddAllGroup() error {
  1556→	if len(a.Groups) == 0 {
  1557→		allGroup := &Group{
  1558→			ID:     xid.New().String(),
  1559→			Name:   "All",
  1560→			Issued: GroupIssuedAPI,
  1561→		}
  1562→		for _, peer := range a.Peers {
  1563→			allGroup.Peers = append(allGroup.Peers, peer.ID)
  1564→		}
  1565→		a.Groups = map[string]*Group{allGroup.ID: allGroup}
  1566→
  1567→		id := xid.New().String()
  1568→
  1569→		defaultPolicy := &Policy{
  1570→			ID:          id,
  1571→			Name:        DefaultRuleName,
  1572→			Description: DefaultRuleDescription,
  1573→			Enabled:     true,
  1574→			Rules: []*PolicyRule{
  1575→				{
  1576→					ID:            id,
  1577→					Name:          DefaultRuleName,
  1578→					Description:   DefaultRuleDescription,
  1579→					Enabled:       true,
  1580→					Sources:       []string{allGroup.ID},
  1581→					Destinations:  []string{allGroup.ID},
  1582→					Bidirectional: true,
  1583→					Protocol:      PolicyRuleProtocolALL,
  1584→					Action:        PolicyTrafficActionAccept,
  1585→				},
  1586→			},
  1587→		}
  1588→
  1589→		a.Policies = []*Policy{defaultPolicy}
  1590→	}
  1591→	return nil
  1592→}
